import { useState, useEffect } from 'react';
import Swal from 'sweetalert2';
import { apiService } from '../utils/apiService';
import Intro from '../components/konzeptes/Intro'; // Verify this path!
import Head from 'next/head';

export default function HomeView() {
  const [isSignup, setIsSignup] = useState(false);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [showPass, setShowPass] = useState(false);

  // Unified Form State
  const [form, setForm] = useState({
    email: '',
    password: '',
    salutation: '',
    p_first: '',
    p_last: '',
    c_first: '',
    c_last: '',
    level: '',
    mobile: '',
  });

  // Check login on load
  useEffect(() => {
    const loggedIn = localStorage.getItem('isLoggedIn');
    if (loggedIn === 'true') {
      setIsLoggedIn(true);
    }
  }, []);

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleAuth = async (e) => {
    e.preventDefault();
    try {
      const action = isSignup ? apiService.register : apiService.login;

      // Map frontend state to backend expected keys
      const payload = isSignup
        ? {
            salutation: form.salutation,
            p_first_name: form.p_first,
            p_last_name: form.p_last,
            c_first_name: form.c_first,
            c_last_name: form.c_last,
            level: form.level,
            mobile: form.mobile,
            email: form.email,
            password: form.password,
          }
        : {
            email: form.email,
            password: form.password,
          };

      const { data } = await action(payload);

      if (data.status === 'success') {
        if (isSignup) {
          await Swal.fire({
            icon: 'success',
            title: 'Success',
            text: 'Account Created! Please Login.',
          });
          setIsSignup(false);
        } else {
          localStorage.setItem('user_id', data.user_id);
          localStorage.setItem('isLoggedIn', 'true');
          localStorage.setItem('child_name', data.child_name || 'Student');
          setIsLoggedIn(true);
        }
      } else {
        Swal.fire({
          icon: 'error',
          title: 'Oops...',
          text: data.message || 'Error occurred',
        });
      }
    } catch (err) {
      console.error(err);
      Swal.fire({
        icon: 'error',
        title: 'Connection Error',
        text: 'Server is not responding',
      });
    }
  };

  // If logged in, show the Dashboard/Intro
  if (isLoggedIn) return <Intro />;

  return (
    <div className="auth-page">
      <Head>
        <title>{isSignup ? 'Register' : 'Login'} | Konzeptes</title>
      </Head>

      <div className={`auth-card ${isSignup ? 'register-mode' : ''}`}>
        <div className="logo-section">
          <img
            src="/lms-system/img/konzeptes/logo.png"
            alt="Konzeptes Logo"
            className="auth-logo"
          />
        </div>

        <h2 className="auth-title">
          {isSignup ? 'Create Account' : 'Welcome Back'}
        </h2>

        <form onSubmit={handleAuth} className="auth-form">
          {isSignup && (
            <div className="registration-grid">
              {/* ROW 1: Title, Parent First, Parent Last */}
              <select
                name="salutation"
                required
                value={form.salutation}
                onChange={handleChange}
                className="span-3"
              >
                <option value="">Title</option>
                <option>Mr.</option>
                <option>Mrs.</option>
                <option>Ms.</option>
              </select>
              <input
                name="p_first"
                placeholder="Parent First Name"
                required
                value={form.p_first}
                onChange={handleChange}
                className="span-4"
              />
              <input
                name="p_last"
                placeholder="Parent Last Name"
                required
                value={form.p_last}
                onChange={handleChange}
                className="span-5"
              />

              {/* ROW 2: Child First, Child Last */}
              <input
                name="c_first"
                placeholder="Child First Name"
                required
                value={form.c_first}
                onChange={handleChange}
                className="span-6"
              />
              <input
                name="c_last"
                placeholder="Child Last Name"
                required
                value={form.c_last}
                onChange={handleChange}
                className="span-6"
              />

              {/* ROW 3: Level, Mobile */}
              <select
                name="level"
                required
                value={form.level}
                onChange={handleChange}
                className="span-5"
              >
                <option value="">Select Level</option>
                <option value="easy">Easy</option>
                <option value="intermediate">Intermediate</option>
                <option value="hard">Hard</option>
              </select>
              <input
                name="mobile"
                placeholder="Mobile Number"
                required
                value={form.mobile}
                onChange={handleChange}
                className="span-7"
              />
            </div>
          )}

          {/* SHARED FIELDS */}
          <input
            name="email"
            type="email"
            placeholder="Email Address"
            className="full-input"
            required
            value={form.email}
            onChange={handleChange}
          />

          <div className="password-wrapper">
            <input
              name="password"
              type={showPass ? 'text' : 'password'}
              placeholder="Password"
              required
              value={form.password}
              onChange={handleChange}
            />
            <span
              className="password-toggle"
              onClick={() => setShowPass(!showPass)}
            >
              {showPass ? '🔒' : '👁️'}
            </span>
          </div>

          <button type="submit" className="auth-submit-btn">
            {isSignup ? 'Sign Up' : 'Login'}
          </button>

          <p className="auth-switch" onClick={() => setIsSignup(!isSignup)}>
            {isSignup
              ? 'Already have an account? Login'
              : "Don't have an account? Create one"}
          </p>
        </form>
      </div>
    </div>
  );
}
